const items = $input.all();

const toStr = (v) => (v == null ? '' : String(v).trim());

const collectPrompts = () => {
  const out = [];
  for (const it of items) {
    // 1. 定位 Gemini 返回的核心文本
    const text = it.json?.candidates?.[0]?.content?.parts?.[0]?.text;
    let s = toStr(text);

    if (s) {
      // 2. 移除开头的 Markdown JSON 标记和方括号
      s = s.replace(/^```json\s*\[?\n?/, '') 
           .replace(/\n?\]?\s*```$/, '')      
           .trim();

      // 3. 彻底清除换行符和各种斜杠
      s = s.replace(/\\n/g, ' ')   // 清理转义换行
           .replace(/\n/g, ' ')     // 清理常规换行
           .replace(/\/n/g, ' ')    // 清理正斜杠换行
           .replace(/\\/g, '')      // 移除所有反斜杠 \
           .replace(/\//g, ' ');    // 移除所有正斜杠 / (替换为空格以防单词粘连)

      // 4. 清理残留的引号标记（可选，如果 AI 输出带引号的话）
      s = s.replace(/\"/g, '');

      // 5. 压缩多余空格
      s = s.replace(/\s+/g, ' ').trim();

      out.push(s);
    }
  }
  return Array.from(new Set(out));
};

const prompts = collectPrompts();

// 最终输出
return [{
  json: {
    prompt: prompts[0] || "" 
  }
}];
